// TestBooleanFlagEvaluation tests successful evaluation of a boolean flag.
func TestBooleanFlagEvaluation(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a boolean flag
		flag, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "boolean-flag",
			Name:         "Boolean Flag",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)
		assert.Equal(t, "boolean-flag", flag.Key)

		// Build the evaluation request
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "test-request-1",
			NamespaceKey: opts.Namespace,
			FlagKey:      "boolean-flag",
			EntityId:     "user123",
			Context: map[string]string{
				"device": "mobile",
			},
		}

		// Marshal request to JSON
		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		// Make HTTP request to evaluate endpoint
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Assert response status
		require.Equal(t, http.StatusOK, resp.StatusCode)

		// Read and unmarshal response
		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var boolResp rpcevaluation.BooleanEvaluationResponse
		err = protojson.Unmarshal(respBody, &boolResp)
		require.NoError(t, err)

		// Verify response fields
		assert.Equal(t, "test-request-1", boolResp.RequestId)
		assert.Equal(t, "boolean-flag", boolResp.FlagKey)
		assert.True(t, boolResp.Enabled)
		assert.NotZero(t, boolResp.RequestDurationMillis)
	})
}

// TestVariantFlagEvaluation tests successful evaluation of a variant flag.
func TestVariantFlagEvaluation(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a variant flag
		flag, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "variant-flag",
			Name:         "Variant Flag",
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create variants
		variantA, err := sdk.Flipt().CreateVariant(ctx, &flipt.CreateVariantRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			Key:          "variant-a",
			Name:         "Variant A",
		})
		require.NoError(t, err)

		variantB, err := sdk.Flipt().CreateVariant(ctx, &flipt.CreateVariantRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			Key:          "variant-b",
			Name:         "Variant B",
		})
		require.NoError(t, err)

		// Create a segment
		segment, err := sdk.Flipt().CreateSegment(ctx, &flipt.CreateSegmentRequest{
			NamespaceKey: opts.Namespace,
			Key:          "test-segment",
			Name:         "Test Segment",
			MatchType:    flipt.MatchType_ALL_MATCH_TYPE,
		})
		require.NoError(t, err)

		// Create a rule
		rule, err := sdk.Flipt().CreateRule(ctx, &flipt.CreateRuleRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			SegmentKey:   "test-segment",
			Rank:         1,
		})
		require.NoError(t, err)

		// Create a distribution for the rule
		_, err = sdk.Flipt().CreateDistribution(ctx, &flipt.CreateDistributionRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			RuleId:       rule.Id,
			VariantId:    variantA.Id,
			Rollout:      100.0,
		})
		require.NoError(t, err)

		// Build the evaluation request
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "test-variant-request",
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			EntityId:     "user456",
			Context: map[string]string{
				"plan": "premium",
			},
		}

		// Marshal request to JSON
		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		// Make HTTP request
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/variant", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Assert response status
		require.Equal(t, http.StatusOK, resp.StatusCode)

		// Read and unmarshal response
		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var variantResp rpcevaluation.VariantEvaluationResponse
		err = protojson.Unmarshal(respBody, &variantResp)
		require.NoError(t, err)

		// Verify response fields
		assert.Equal(t, "test-variant-request", variantResp.RequestId)
		assert.Equal(t, "variant-flag", variantResp.FlagKey)
		assert.True(t, variantResp.Match)
		assert.NotEmpty(t, variantResp.VariantKey)
		assert.NotZero(t, variantResp.RequestDurationMillis)

		_ = flag
		_ = variantB
		_ = segment
	})
}

// TestFlagNotFound tests that evaluating a non-existent flag returns appropriate error.
func TestFlagNotFound(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		// Build evaluation request for a flag that doesn't exist
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "test-not-found",
			NamespaceKey: opts.Namespace,
			FlagKey:      "non-existent-flag",
			EntityId:     "user789",
		}

		// Marshal request to JSON
