		require.NoError(t, err)

		// Make HTTP request
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Assert error status (should be 4xx or 5xx)
