			Name:         "Boolean Flag",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Build evaluation request for variant endpoint (wrong endpoint for boolean flag)
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "test-wrong-type",
			NamespaceKey: opts.Namespace,
			FlagKey:      "boolean-only-flag",
			EntityId:     "user999",
		}

		// Marshal request to JSON
